class Solution {
    public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        firstPlayer--; secondPlayer--;
        int[] res = new int[]{Integer.MAX_VALUE, Integer.MIN_VALUE};
        dfs(0, n, firstPlayer, secondPlayer, 0, res);
        return new int[]{res[0], res[1]};
    }

    private void dfs(int start, int end, int firstPlayer, int secondPlayer, int round, int[] res) {
        if (start >= end) {
            res[0] = Math.min(res[0], round);
            res[1] = Math.max(res[1], round);
            return;
        }
        int mid = (start + end) / 2;
        if (firstPlayer <= mid && secondPlayer <= mid) {
            dfs(start, mid, firstPlayer, secondPlayer, round + 1, res);
        } else if (firstPlayer > mid && secondPlayer > mid) {
            dfs(mid + 1, end, firstPlayer - mid - 1, secondPlayer - mid - 1, round + 1, res);
        } else {
            if (firstPlayer == start && secondPlayer == end) {
                dfs(start + 1, end - 1, -1, -1, round + 1, res);
            } else {
                dfs(start, mid, Math.min(firstPlayer, start), Math.max(secondPlayer - (end - mid), mid + 1) - start, round + 1, res);
                dfs(mid + 1, end, Math.min(firstPlayer - (mid + 1), mid - start), Math.max(secondPlayer, end) - (mid + 1), round + 1, res);
            }
        }
    }
}
